#!/bin/sh
set -e

# The tui / openai-server / fat-station arms do NOT need a moonshine identity.
# `moonshine init` writes $HOME/.moonshine.knot, which fails with EACCES on a
# read-only / non-writable HOME (e.g. Cloud Run, where only /tmp is writable).
# So dispatch those arms FIRST and only run the identity init for the default
# moonshine daemon at the bottom.

find_local_knot_candidate() {
  base="$(basename "$KNOT_URL")"
  for candidate in \
    "${MOONSHINE_KNOT_LOCAL_PATH:-}" \
    "/data/knots/$base" \
    "/tmp/$base"; do
    if [ -n "$candidate" ] && [ -r "$candidate" ]; then
      printf '%s\n' "$candidate"
      return 0
    fi
  done
  return 1
}

download_knot_to_path() {
  out="$1"
  export KNOT_PATH="$out"
  echo "[entrypoint] downloading knot $KNOT_URL -> $KNOT_PATH (chunked Range + backoff)"
  cat > /tmp/dlknot.mjs <<'DLEOF'
import fs from 'node:fs';
const url = process.env.KNOT_URL, out = process.env.KNOT_PATH;
const CHUNK = 64 * 1024 * 1024;
const f = fs.createWriteStream(out);
let pos = 0;
for (;;) {
  let chunk = null;
  for (let a = 0; a < 12; a++) {
    try {
      const r = await fetch(url, { headers: { Range: `bytes=${pos}-${pos + CHUNK - 1}` } });
      if (r.status === 206 || r.status === 200) { chunk = Buffer.from(await r.arrayBuffer()); break; }
      if (r.status >= 500 || r.status === 429) { await new Promise(s => setTimeout(s, 1500 * (a + 1))); continue; }
      console.error('[entrypoint] knot dl HTTP ' + r.status); process.exit(1);
    } catch (e) { await new Promise(s => setTimeout(s, 1500 * (a + 1))); }
  }
  if (chunk === null) { console.error('[entrypoint] knot dl gave up at byte ' + pos); process.exit(1); }
  if (chunk.length === 0) break;
  await new Promise((res, rej) => f.write(chunk, e => e ? rej(e) : res()));
  pos += chunk.length;
  if (chunk.length < CHUNK) break;
}
f.end();
console.error('[entrypoint] knot downloaded ' + pos + ' bytes -> ' + out);
DLEOF
  node /tmp/dlknot.mjs || { echo "[entrypoint] knot download failed" >&2; exit 1; }
}

start_background_knot_localizer() {
  if [ "${MOONSHINE_KNOT_BACKGROUND_LOCALIZE:-1}" = "0" ]; then
    return 0
  fi
  target="/tmp/$(basename "$KNOT_URL")"
  if [ -r "$target" ]; then
    return 0
  fi
  (
    tmp="${target}.partial.$$"
    if KNOT_PATH="$tmp" download_knot_to_path "$tmp"; then
      mv "$tmp" "$target"
      echo "[entrypoint] background knot localizer ready: $target"
    else
      rm -f "$tmp"
      echo "[entrypoint] background knot localizer failed" >&2
    fi
  ) &
}

# select_fat_station_bin: pick the cuBLAS-built fat-station when the Cloud Run
# GPU driver injection is present (libcuda.so.1 under /usr/local/nvidia). The
# cuda binary is dynamic-LINKED against libcuda, so launching it without the
# driver fails at exec — never select it blind. Explicit FAT_STATION_BIN wins.
select_fat_station_bin() {
  if [ -n "${FAT_STATION_BIN:-}" ]; then
    echo "[entrypoint] FAT_STATION_BIN=$FAT_STATION_BIN (explicit)" >&2
    return
  fi
  if command -v fat-station-cuda >/dev/null 2>&1 && \
     { [ -e /usr/local/nvidia/lib64/libcuda.so.1 ] || [ -e /usr/local/nvidia/lib/libcuda.so.1 ]; }; then
    FAT_STATION_BIN=fat-station-cuda
    echo "[entrypoint] NVIDIA driver detected — using fat-station-cuda (cuBLAS L4 backend)" >&2
  else
    FAT_STATION_BIN=fat-station
  fi
}

# download_weights: select a knot source and, if set, the Qwen2 tokenizer GGUF.
# Sets KNOT_PATH and TOKENIZER_GGUF_PATH for the caller. Shared by the
# openai-server and fat-station arms.
download_weights() {
  if [ -z "$KNOT_URL" ]; then
    echo "[entrypoint] KNOT_URL is required" >&2
    exit 1
  fi
  # fat-station mmaps LOCAL paths (RAM-resident, fast) and can RANGE-FETCH
  # http(s) URLs. Cloud cold starts should normally stream the URL so the host
  # can become reachable immediately; warm/resident paths may choose download
  # to put the whole knot in /tmp before inference. `race` lets any mounted or
  # already-localized path win, then falls back to HTTP Range with persistent
  # usage-driven caching.
  : "${MOONSHINE_KNOT_LOAD_MODE:=download}"
  KNOT_PATH="$KNOT_URL"
  case "$KNOT_URL" in
    http://*|https://*)
      if [ "$MOONSHINE_KNOT_LOAD_MODE" = "race" ] || [ "$MOONSHINE_KNOT_LOAD_MODE" = "auto" ]; then
        if local_knot="$(find_local_knot_candidate)"; then
          KNOT_PATH="$local_knot"
          echo "[entrypoint] raced knot source winner: local mmap $KNOT_PATH"
        else
          KNOT_PATH="$KNOT_URL"
          : "${KNOT_RANGE_CACHE_DIR:=/tmp/knot-range-cache}"
          export KNOT_RANGE_CACHE_DIR
          echo "[entrypoint] raced knot source winner: HTTP Range $KNOT_URL (cache: $KNOT_RANGE_CACHE_DIR)"
          start_background_knot_localizer
        fi
        export KNOT_PATH
      elif [ "$MOONSHINE_KNOT_LOAD_MODE" = "stream" ] || [ "$MOONSHINE_KNOT_LOAD_MODE" = "range" ]; then
        echo "[entrypoint] streaming knot via fat-station Range reads: $KNOT_URL"
        : "${KNOT_RANGE_CACHE_DIR:=/tmp/knot-range-cache}"
        export KNOT_RANGE_CACHE_DIR
        export KNOT_PATH
      else
        download_knot_to_path "/tmp/$(basename "$KNOT_URL")"
      fi
      ;;
  esac

  # Qwen models need a Qwen2 tokenizer GGUF (tokenizer.ggml.tokens + merges) for
  # BOTH fat-station (/tokenize,/detokenize) AND openai-server (ChatML + BPE).
  # Header-truncated GGUF (~12MB: header + metadata, no tensors).
  if [ -n "$TOKENIZER_GGUF_URL" ]; then
    TOKENIZER_GGUF_PATH="/tmp/$(basename "$TOKENIZER_GGUF_URL")"
    export TOKENIZER_GGUF_PATH
    echo "[entrypoint] downloading tokenizer $TOKENIZER_GGUF_URL -> $TOKENIZER_GGUF_PATH"
    node -e "const fs=require('fs');(async()=>{for(let a=0;a<8;a++){try{const r=await fetch(process.env.TOKENIZER_GGUF_URL);if(r.ok){fs.writeFileSync(process.env.TOKENIZER_GGUF_PATH,Buffer.from(await r.arrayBuffer()));console.error('[entrypoint] tokenizer downloaded');process.exit(0);}if(r.status>=500||r.status===429){await new Promise(s=>setTimeout(s,1000*(a+1)));continue;}console.error('[entrypoint] tokenizer dl HTTP '+r.status);process.exit(1);}catch(e){await new Promise(s=>setTimeout(s,1000*(a+1)));}}console.error('[entrypoint] tokenizer dl gave up');process.exit(1);})()" \
      || { echo "[entrypoint] tokenizer download failed" >&2; exit 1; }
  fi
}

default_layer_count() {
  case "$(printf '%s' "${MODEL_NAME:-}" | tr '[:upper:]' '[:lower:]')" in
    *mistral*) echo "32" ;;
    *qwen*0.5*) echo "24" ;;
    *qwen*7b*|*coder*7b*) echo "28" ;;
    *) echo "28" ;;
  esac
}

resolve_fat_station_layers() {
  if [ -n "${FAT_STATION_LAYERS:-}" ]; then
    printf '%s\n' "$FAT_STATION_LAYERS"
    return 0
  fi

  LAYER_COUNT="$(node - <<'LAYEREOF' 2>/dev/null || true
import fs from 'node:fs';

const knotPath = process.env.KNOT_PATH;
if (!knotPath) process.exit(1);

const fd = fs.openSync(knotPath, 'r');
try {
  const head = Buffer.alloc(10);
  fs.readSync(fd, head, 0, head.length, 0);
  if (head.subarray(0, 4).toString('utf8') !== 'KNOT') process.exit(1);
  const metaLength = head.readUInt32LE(6);
  const meta = Buffer.alloc(metaLength);
  fs.readSync(fd, meta, 0, metaLength, head.length);
  const json = JSON.parse(meta.toString('utf8'));
  const layers = Number(json?.config?.num_layers);
  if (!Number.isInteger(layers) || layers <= 0) process.exit(1);
  console.log(layers);
} finally {
  fs.closeSync(fd);
}
LAYEREOF
)"

  if [ -z "$LAYER_COUNT" ]; then
    LAYER_COUNT="$(default_layer_count)"
  fi
  printf '0..%s\n' "$LAYER_COUNT"
}

if [ "$1" = "tui" ]; then
  shift
  exec node --import tsx /app/open-source/aeon-tui/src/main.tsx "$@"
fi

# fat-station arm: serve fat-station DIRECTLY on $PORT. Used by the MolmoAct2
# vision-language-action service — its POST /action endpoint must be externally
# reachable on the Cloud Run PORT (openai-server only proxies the chat path).
if [ "$1" = "fat-station" ]; then
  shift
  export HOME="${HOME:-/tmp}"
  cd /app || true
  : "${PORT:=8080}"
  export PORT MODEL_NAME
  download_weights
  FAT_STATION_LAYERS_EFFECTIVE="$(resolve_fat_station_layers)"
  export FAT_STATION_LAYERS_EFFECTIVE
  select_fat_station_bin
  echo "[entrypoint] starting $FAT_STATION_BIN --knot $KNOT_PATH --port $PORT --role both --layers $FAT_STATION_LAYERS_EFFECTIVE (direct serve)"
  exec "$FAT_STATION_BIN" --knot "$KNOT_PATH" --port "$PORT" --role both --layers "$FAT_STATION_LAYERS_EFFECTIVE" "$@"
fi

# mesh arm: the SINGLE consolidated mesh service. Runs mesh-supervisor, which
# fronts $PORT and spawns the openai-server arm (this same script) as a child on
# an internal port with one model's env, swapping the model on demand. One GPU
# slot for all models — replaces the ~10 per-model services. No baked knot:
# models load from R2 on demand via the child arm.
if [ "$1" = "mesh" ]; then
  shift
  export HOME="${HOME:-/tmp}"
  cd /app/open-source/gnosis || true
  : "${PORT:=8080}"
  : "${MESH_CHILD_PORT:=8090}"
  export PORT MESH_CHILD_PORT
  export MESH_ENTRYPOINT="${MESH_ENTRYPOINT:-$0}"
  SUP_TS=/app/open-source/gnosis/distributed-inference-host/src/bin/mesh-supervisor.ts
  GNODE_JS="${GNODE_JS_PATH:-/app/open-source/gnosis/bin/gnode.js}"
  if [ "${MOONSHINE_OPENAI_RUNTIME:-gnode}" != "node" ] && [ -f "$GNODE_JS" ]; then
    echo "[entrypoint] launching mesh-supervisor via gnode: $GNODE_JS run $SUP_TS"
    exec node "$GNODE_JS" run "$SUP_TS" "$@"
  fi
  echo "[entrypoint] launching mesh-supervisor via node+tsx (legacy runtime)"
  exec node --import tsx "$SUP_TS" "$@"
fi

if [ "$1" = "openai-server" ]; then
  shift
  # Run from @a0n/gnosis so `node --import tsx` resolves tsx from that package.
  export HOME="${HOME:-/tmp}"
  cd /app/open-source/gnosis || true
  : "${FAT_STATION_PORT:=8000}"
  : "${PORT:=8080}"
  : "${FAT_STATION_URL:=http://127.0.0.1:${FAT_STATION_PORT}}"
  export FAT_STATION_PORT PORT FAT_STATION_URL MODEL_NAME

  # Mesh coordinator mode: when MESH_STATION_URLS is set this process is normally
  # a PURE coordinator — NO local fat-station, NO knot download. The openai-server
  # reads MESH_* env (resolveOpenAiServerMeshConfig) and drives remote GPU layer
  # stations over HTTP (/embed,/forward,/lm-head). MESH_LOCAL_STATION=1 is the
  # single-container exception: start the local fat-station below, then launch the
  # openai-server with MESH_* still present so it coordinates against localhost.
  if [ -n "${MESH_STATION_URLS:-}" ] && [ "${MESH_LOCAL_STATION:-0}" != "1" ]; then
    echo "[entrypoint] MESH COORDINATOR mode: stations=${MESH_STATION_URLS} ranges=${MESH_LAYER_RANGES:-?} hidden=${MESH_HIDDEN_DIM:-?} vocab=${MESH_VOCAB_SIZE:-?} (no local fat-station / no knot)"
    cd /app/open-source/gnosis || true
    # Coordinator tokenizer fetch (70b-gpu-mesh-runbook.md §6): the mesh-coordinator
    # branch skips download_weights, but the qwen2/byte-BPE tokenizer loader needs a
    # LOCAL gguf (existsSync TOKENIZER_GGUF_PATH). Fetch it here so a sharded 70B
    # coordinator can tokenize (retry loop mirrors the fat-station tokenizer download).
    if [ -n "${TOKENIZER_GGUF_URL:-}" ] && [ ! -r "${TOKENIZER_GGUF_PATH:-/dev/null}" ]; then
      echo "[entrypoint] coordinator: downloading tokenizer ${TOKENIZER_GGUF_URL} -> ${TOKENIZER_GGUF_PATH}"
      node -e "const fs=require('fs');(async()=>{for(let a=0;a<8;a++){try{const r=await fetch(process.env.TOKENIZER_GGUF_URL);if(r.ok){fs.writeFileSync(process.env.TOKENIZER_GGUF_PATH,Buffer.from(await r.arrayBuffer()));console.error('[entrypoint] coordinator tokenizer downloaded');process.exit(0);}await new Promise(s=>setTimeout(s,1000*(a+1)));}catch(e){await new Promise(s=>setTimeout(s,1000*(a+1)));}}console.error('[entrypoint] coordinator tokenizer dl failed');process.exit(1);})()" || echo "[entrypoint] WARN coordinator tokenizer dl failed — falling back to byte tokenizer"
    fi
    OPENAI_TS=/app/open-source/gnosis/distributed-inference-host/src/bin/openai-server.ts
    GNODE_JS="${GNODE_JS_PATH:-/app/open-source/gnosis/bin/gnode.js}"
    if [ "${MOONSHINE_OPENAI_RUNTIME:-gnode}" != "node" ] && [ -f "$GNODE_JS" ]; then
      echo "[entrypoint] launching mesh-coordinator openai-server via gnode: $GNODE_JS run $OPENAI_TS"
      exec node "$GNODE_JS" run "$OPENAI_TS" "$@"
    fi
    echo "[entrypoint] launching mesh-coordinator openai-server via node+tsx (legacy runtime)"
    exec node --import tsx "$OPENAI_TS" "$@"
  fi

  cat > /tmp/moonshine-warmup-server.mjs <<'WARMEOF'
import http from 'node:http';

const port = Number(process.env.PORT ?? 8080);
const startedAt = Date.now();

const server = http.createServer((req, res) => {
  const body = JSON.stringify({
    status: 'warming',
    code: 'model_warming',
    message: 'Moonshine is downloading and loading the model knot.',
    uptime_ms: Date.now() - startedAt,
    model: process.env.MODEL_NAME ?? 'unknown',
  });
  res.writeHead(503, {
    'Content-Type': 'application/json',
    'Cache-Control': 'no-store',
  });
  res.end(body);
});

server.listen(port, '0.0.0.0', () => {
  console.error(`[entrypoint] warmup server listening on :${port}`);
});

// HARD exit on signal — do NOT server.close() (it waits for in-flight keep-alive
// connections to drain, and a client polling the 503s keeps the socket alive, so
// close() hangs → the warmup process zombies holding $PORT → the real openai-server
// can never bind it → EADDRINUSE crash-loop on every model swap. The warmup has no
// state to flush, so exit immediately and free the port for the real server.
process.on('SIGTERM', () => process.exit(0));
process.on('SIGINT', () => process.exit(0));
WARMEOF
  node /tmp/moonshine-warmup-server.mjs &
  WARMUP_PID=$!

  stop_warmup() {
    if kill -0 "$WARMUP_PID" 2>/dev/null; then
      kill "$WARMUP_PID" 2>/dev/null || true
      wait "$WARMUP_PID" 2>/dev/null || true
    fi
  }

  trap 'stop_warmup; [ -n "${FAT_STATION_PID:-}" ] && kill "$FAT_STATION_PID" 2>/dev/null || true; exit 143' TERM INT

  download_weights

  FAT_STATION_LAYERS_EFFECTIVE="$(resolve_fat_station_layers)"
  export FAT_STATION_LAYERS_EFFECTIVE
  select_fat_station_bin
  echo "[entrypoint] starting $FAT_STATION_BIN --knot $KNOT_PATH --port $FAT_STATION_PORT --role both --layers $FAT_STATION_LAYERS_EFFECTIVE"
  "$FAT_STATION_BIN" --knot "$KNOT_PATH" --port "$FAT_STATION_PORT" --role both --layers "$FAT_STATION_LAYERS_EFFECTIVE" &
  FAT_STATION_PID=$!

  # Poll fat-station /health until ready (knot download + load can take a while).
  echo "[entrypoint] waiting for fat-station /health on 127.0.0.1:${FAT_STATION_PORT} ..."
  i=0
  until node -e "fetch('http://127.0.0.1:'+process.env.FAT_STATION_PORT+'/health').then(r=>process.exit(r.ok?0:1)).catch(()=>process.exit(1))" 2>/dev/null; do
    if ! kill -0 "$FAT_STATION_PID" 2>/dev/null; then
      echo "[entrypoint] fat-station exited before becoming healthy" >&2
      wait "$FAT_STATION_PID" 2>/dev/null
      exit 1
    fi
    i=$((i + 1))
    if [ "$i" -ge "${FAT_STATION_HEALTH_TIMEOUT_S:-900}" ]; then
      echo "[entrypoint] timed out waiting for fat-station /health after ${i}s" >&2
      kill "$FAT_STATION_PID" 2>/dev/null
      exit 1
    fi
    sleep 1
  done
  echo "[entrypoint] fat-station healthy; launching openai-server on :${PORT} -> ${FAT_STATION_URL}"

  stop_warmup
  # The warmup server (and a prior crash-looped openai-server) can linger on $PORT
  # for a moment after kill; the exec'd openai-server binding it immediately →
  # `EADDRINUSE :$PORT` crash-loop. This bites hard on slow-boot models (falcon-mamba
  # streams an 8GB knot, so the warmup server runs long and the boot window is wide).
  # Wait until $PORT actually refuses connections before handing it to the real server.
  echo "[entrypoint] waiting for :${PORT} to free before openai-server bind ..."
  pj=0
  while node -e "const s=require('net').connect({port:+process.env.PORT,host:'127.0.0.1'},()=>{s.destroy();process.exit(0)});s.on('error',()=>process.exit(1));setTimeout(()=>{s.destroy();process.exit(1)},500)" 2>/dev/null; do
    pj=$((pj + 1)); [ "$pj" -ge 40 ] && { echo "[entrypoint] :${PORT} still busy after 10s — binding anyway" >&2; break; }
    sleep 0.25
  done

  run_openai_server_with_fat_station_monitor() {
    "$@" &
    OPENAI_PID=$!
    trap 'kill "$OPENAI_PID" "$FAT_STATION_PID" 2>/dev/null || true; exit 143' TERM INT
    while :; do
      if ! kill -0 "$FAT_STATION_PID" 2>/dev/null; then
        echo "[entrypoint] fat-station exited while openai-server was running; terminating child" >&2
        kill "$OPENAI_PID" 2>/dev/null || true
        set +e
        wait "$FAT_STATION_PID" 2>/dev/null
        FAT_STATUS=$?
        wait "$OPENAI_PID" 2>/dev/null
        set -e
        exit "$FAT_STATUS"
      fi
      if ! kill -0 "$OPENAI_PID" 2>/dev/null; then
        set +e
        wait "$OPENAI_PID" 2>/dev/null
        OPENAI_STATUS=$?
        kill "$FAT_STATION_PID" 2>/dev/null || true
        wait "$FAT_STATION_PID" 2>/dev/null
        set -e
        exit "$OPENAI_STATUS"
      fi
      sleep 1
    done
  }

  # Runtime for the openai-server TS shim. monster/gnode is the sovereign
  # polyglot runner (proven in prod on the 70B gcp-layer-node.ts) and starts +
  # executes TS faster than node+tsx. Default to gnode; MOONSHINE_OPENAI_RUNTIME=node
  # forces the legacy node+tsx path. The compute hot path is the native Rust
  # fat-station binary regardless — this only governs the orchestration shim.
  OPENAI_TS=/app/open-source/gnosis/distributed-inference-host/src/bin/openai-server.ts
  GNODE_JS="${GNODE_JS_PATH:-/app/open-source/gnosis/bin/gnode.js}"
  if [ "${MOONSHINE_OPENAI_RUNTIME:-gnode}" != "node" ] && [ -f "$GNODE_JS" ]; then
    echo "[entrypoint] launching openai-server via gnode (monster runner): $GNODE_JS run $OPENAI_TS"
    run_openai_server_with_fat_station_monitor node "$GNODE_JS" run "$OPENAI_TS" "$@"
  fi
  echo "[entrypoint] launching openai-server via node+tsx (legacy runtime)"
  run_openai_server_with_fat_station_monitor node --import tsx "$OPENAI_TS" "$@"
fi

# Default: the moonshine daemon — needs an identity at $HOME/.moonshine.knot.
if [ ! -f "$HOME/.moonshine.knot" ]; then
  if [ -n "$MOONSHINE_DID" ]; then
    moonshine init --did "$MOONSHINE_DID" --secret "$MOONSHINE_SECRET"
  else
    moonshine init
  fi
fi

exec moonshine "$@"
